const items = $input.all();

let highRisk = 0;
let losses = 0;

items.forEach(item => {
  const current = Number(item.json["Current Value"]);
  const last = Number(item.json["Last Week Value"]);
  const risk = item.json["Risk Level"];

  if (risk === "High") highRisk++;
  if (current < last) losses++;
});

return [{
  json: {
    PortfolioSummary: `
High Risk Assets: ${highRisk}
Assets Losing Value: ${losses}
`
  }
}];
